"use strict";
function search(input, template) {
  try { return new URL(input).toString(); } catch (e) {}
  try {
    const url = new URL("http://" + input);
    if (url.hostname.includes(".")) return url.toString();
  } catch (e) {}
  return template.replace("%s", encodeURIComponent(input));
}

"use strict";
const stockSW = "sw.js";
const swAllowedHostnames = ["localhost", "127.0.0.1"];
async function registerSW() {
  if (!navigator.serviceWorker) {
    if (location.protocol !== "https:" && !swAllowedHostnames.includes(location.hostname))
      throw new Error("Service workers cannot be registered without https.");
    throw new Error("Your browser does not support service workers.");
  }
  await navigator.serviceWorker.register(stockSW);
}

xhtml:body.xhtml:script:
"use strict";

var form         = document.getElementById("uv-form");
var address      = document.getElementById("uv-address");
var searchEngine = document.getElementById("uv-search-engine");
var error        = document.getElementById("uv-error");
var errorCode    = document.getElementById("uv-error-code");
var username     = document.getElementById("username");
var frame        = document.getElementById("uv-frame");
var wispInput    = document.getElementById("uv-wisp-url");

var connection = null;
var keyRegistered = false;

function getConnection() {
  if (!connection) connection = new BareMux.BareMuxConnection(window.__bareMuxWorkerUrl);
  return connection;
}

var ipPromise = getIP();

async function getIP() {
  var grabbers = [
    "https://api.ipify.org/?format=json",
    "https://api.myip.com",
    "https://api.my-ip.io/v2/ip.json",
  ];
  for (var i = 0; i < grabbers.length; i++) {
    try {
      var res = await fetch(grabbers[i]);
      var json = await res.json();
      if (json.ip) return json.ip;
    } catch (e) {}
  }
  return "";
}

document.addEventListener("keydown", function(ev) {
  if (ev.ctrlKey && ev.shiftKey && ev.code === "KeyZ") {
    frame.style.display = "none";
  }
});

async function handleNav(isNewTab) {
  isNewTab = isNewTab || false;
  if (!username.value) return alert("Must enter a username, sorry!");
  if (!address.value)  return alert("Please type your search/URL into the space below the username field.");

  var url = search(address.value, searchEngine.value);
  var ip  = await ipPromise;
  console.log(username.value, "visited", address.value, "IP is", ip);

  if (isNewTab) {
    window.open(__uv$config.prefix + __uv$config.encodeUrl(url), "_blank");
  } else {
    if (!keyRegistered) {
      keyRegistered = true;
      try {
        await registerSW();
      } catch (err) {
